mapper.select:
select u.user_id, u.dept_id, u.nick_name, u.real_name, u.email, u.avatar, u.sex, u.city, u.status, u.del_flag, u.ext_info, u.create_by, u.create_time, u.remark, d.dept_name, d.leader from sys_user u left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.nick_name like concat('%', #{nickName}, '%')
AND u.status = #{status}
AND date_format(u.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
AND date_format(u.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE #{deptId} = any(string_to_array(ancestors, ',')) ))
${params.dataScope}

select distinct u.user_id, u.dept_id, u.nick_name, u.real_name, u.email, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.nick_name like concat('%', #{nickName}, '%')
${params.dataScope}

select distinct u.user_id, u.dept_id, u.nick_name, u.real_name, u.email, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and (r.role_id != #{roleId} or r.role_id IS NULL) and u.user_id not in (select u.user_id from sys_user u inner join sys_user_role ur on u.user_id = ur.user_id and ur.role_id = #{roleId})
AND u.nick_name like concat('%', #{nickName}, '%')
${params.dataScope}

mapper.update:
update sys_user
dept_id = #{deptId}, nick_name = #{nickName}, real_name = #{realName}, email = #{email}, sex = #{sex}, avatar = #{avatar}, city = #{city}, status = #{status}, update_by = #{updateBy}, remark = #{remark}, update_time = current_timestamp
where user_id = #{userId}
